#!/bin/bash
# .claude/hooks/protect-files.sh
#
# Fires on PreToolUse for Edit and Write. Blocks edits to protected files:
# .env files (secrets), lockfiles (regenerated by package managers).
#
# Exits 2 with a reason in stderr to block the edit. Exits 0 otherwise.
#
# Register in .claude/settings.json under hooks.PreToolUse with matcher
# "Edit|Write".

set -u

INPUT=$(cat)
FILE_PATH=$(echo "$INPUT" | jq -r '.tool_input.file_path // empty')

[ -z "$FILE_PATH" ] && exit 0

# Get just the basename for cleaner pattern matching
BASENAME=$(basename "$FILE_PATH")

# Protected file patterns
case "$BASENAME" in
  .env|.env.*|*.env)
    echo "Refusing to edit protected file: $FILE_PATH (contains secrets)" >&2
    exit 2
    ;;
  package-lock.json|yarn.lock|bun.lockb|pnpm-lock.yaml|Cargo.lock|Gemfile.lock|poetry.lock|uv.lock|composer.lock|Pipfile.lock)
    echo "Refusing to edit lockfile: $FILE_PATH (run the package manager command instead)" >&2
    exit 2
    ;;
esac

exit 0
